function mysteryFunction(n, memo = {}) {
  if (n <= 1) return n;
  if (memo[n]) return memo[n];

  const left = mysteryFunction(n >> 1, memo);
  const right = mysteryFunction(n >> 2, memo);
  memo[n] = left + right + (n & 1);

  return memo[n];
}

